/**
 * @name SFTP path taint flow from network input to file operations
 * @description Trace user-supplied paths from SFTP operations to filesystem access
 * @kind path-problem
 * @problem.severity error
 * @id java/sftp-path-taint
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module SftpPathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // SFTP reads strings from the buffer (user-controlled)
    exists(MethodCall mc |
      mc.getMethod().hasName("getString") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.sshd.common.util.buffer", "Buffer") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Path resolution from user string
    exists(MethodCall mc |
      mc.getMethod().hasName("getPath") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.nio.file", "FileSystem") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module SftpPathFlow = TaintTracking::Global<SftpPathConfig>;
import SftpPathFlow::PathGraph

from SftpPathFlow::PathNode source, SftpPathFlow::PathNode sink
where SftpPathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User-controlled SFTP path flows from $@ to filesystem path construction", source.getNode(), "Buffer.getString()"
